-- description: Distinct entities with labels, type information, and statement counts for UI views

with entity_refs as ( select s.subject_fingerprint as entity_fingerprint, s.subject_type as entity_type, s.subject_reference_type as entity_reference_type, subj.reference_identifier as reference_identifier from statements s inner join reference_identifiers subj on subj.identifier_fingerprint = s.subject_fingerprint union all select s.object_fingerprint as entity_fingerprint, s.object_type as entity_type, s.object_reference_type as entity_reference_type, obj.reference_identifier as reference_identifier from statements s inner join reference_identifiers obj on obj.identifier_fingerprint = s.object_fingerprint ), labels as ( select s.subject_fingerprint as entity_fingerprint, obj.reference_identifier as label from statements s inner join reference_identifiers pred on pred.identifier_fingerprint = s.predicate_fingerprint inner join reference_identifiers obj on obj.identifier_fingerprint = s.object_fingerprint where pred.reference_identifier = 'https://www.w3.org/2000/01/rdf-schema#label' and s.object_type = 'a0' ), entity_stats as ( select entity_fingerprint, min(entity_type) as entity_type, min(entity_reference_type) as entity_reference_type, min(reference_identifier) as reference_identifier, count(*) as mention_count from entity_refs group by entity_fingerprint ) select e.entity_fingerprint, e.entity_type, e.entity_reference_type, e.reference_identifier, min(l.label) as label, e.mention_count from entity_stats e left join labels l on l.entity_fingerprint = e.entity_fingerprint group by e.entity_fingerprint, e.entity_type, e.entity_reference_type, e.reference_identifier, e.mention_count order by e.mention_count desc, coalesce(min(l.label), e.reference_identifier) asc
